interface ServiceCheck {
  name: string;
  ok: boolean;
  status: number | null;
  url: string;
}

const DEFAULT_APP_BASE_URL = "http://localhost:3024";
const DEFAULT_PLATFORM_BASE_URL = "http://localhost:4112";

async function checkUrl(name: string, url: string): Promise<ServiceCheck> {
  try {
    const response = await fetch(url, {
      method: "GET",
      signal: AbortSignal.timeout(3_000),
    });

    return {
      name,
      url,
      status: response.status,
      ok: response.ok,
    };
  } catch {
    return {
      name,
      url,
      status: null,
      ok: false,
    };
  }
}

export async function doctor(): Promise<ServiceCheck[]> {
  return Promise.all([
    checkUrl("platform health", `${DEFAULT_PLATFORM_BASE_URL}/api/health`),
    checkUrl("platform inngest", `${DEFAULT_PLATFORM_BASE_URL}/api/inngest`),
    checkUrl("app ingress proxy", `${DEFAULT_APP_BASE_URL}/api/inngest`),
  ]);
}

